        int sl, sr, sc;
        for (int l = 0; l < L; l++)
            for (int r = 0; r < R; r++) {
                cin >> grid[l][r];
                for (int c = 0; c < C; c++)
                    if (grid[l][r][c] == 'S') sl = l, sr = r, sc = c;
            }

        queue<tuple<int,int,int,int>> q;
        q.push({sr, sc, sl, 0});
        vector<vector<vector<bool>>> vis(L, vector<vector<bool>>(R, vector<bool>(C, false)));
        vis[sl][sr][sc] = true;

        int dr[] = {0,0,0,0,1,-1};
        int dc[] = {0,0,1,-1,0,0};
        int dl[] = {1,-1,0,0,0,0};

        bool found = false;
        while (!q.empty() && !found) {
            auto [r, c, l, d] = q.front(); q.pop();
            if (grid[l][r][c] == 'E') {
                cout << "Escaped in " << d << " minute(s).\n";
                found = true;
            }
            for (int i = 0; i < 6; i++) {
                int nr = r+dr[i], nc = c+dc[i], nl = l+dl[i];
                if (nl >= 0 && nl < L && nr >= 0 && nr < R && nc >= 0 && nc < C &&
                    !vis[nl][nr][nc] && grid[nl][nr][nc] != '#') {
                    vis[nl][nr][nc] = true;
                    q.push({nr, nc, nl, d+1});
                }
            }
        }
        if (!found) cout << "Trapped!\n";
    }
